SELECT /* base.sy :: SyhAlarmSendHist :: selectList */ h.* , ste.site_nm AS site_nm FROM syh_alarm_send_hist h LEFT JOIN sy_site ste ON ste.site_id = h.site_id
ORDER BY h.send_hist_id ASC ORDER BY h.send_hist_id DESC ORDER BY h.send_date ASC ORDER BY h.send_date DESC ORDER BY h.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

SELECT /* base.sy :: SyhAlarmSendHist :: selectPageList */ h.* , ste.site_nm AS site_nm FROM syh_alarm_send_hist h LEFT JOIN sy_site ste ON ste.site_id = h.site_id
ORDER BY h.send_hist_id ASC ORDER BY h.send_hist_id DESC ORDER BY h.send_date ASC ORDER BY h.send_date DESC ORDER BY h.reg_date DESC
LIMIT #{limit} OFFSET #{offset}
